#### **任务 6: 前端 WebSocket 管理器完善**
**工作量**: 1 天 | **文件**: `dashboard/src/utils/websocket-manager.ts`

```typescript
// dashboard/src/utils/websocket-manager.ts

import { ref, reactive } from 'vue'

export enum ConnectionState {
  DISCONNECTED = 'disconnected',
  CONNECTING = 'connecting',
  CONNECTED = 'connected',
  RECONNECTING = 'reconnecting',
  ERROR = 'error'
}

export function useWebSocket(url?: string) {
  const wsUrl = url || `ws://${window.location.host}/api/ws`

  const state = reactive({
    connected: false,
    connectionState: ConnectionState.DISCONNECTED,
    reconnectAttempts: 0,
    lastError: null as Error | null,
    maxReconnectAttempts: 5,
    reconnectDelay: 1000
  })

  let ws: WebSocket | null = null
  let reconnectTimer: any = null
  let eventHandlers: Map<string, Function[]> = new Map()

  const connect = () => {
    if (state.connectionState === ConnectionState.CONNECTING || 
        state.connectionState === ConnectionState.CONNECTED) {
      return
    }

    state.connectionState = ConnectionState.CONNECTING
    state.lastError = null

    try {
      ws = new WebSocket(wsUrl)

      ws.onopen = () => {
        state.connected = true
        state.connectionState = ConnectionState.CONNECTED
        state.reconnectAttempts = 0
        emit('connected')
      }

      ws.onmessage = (event) => {
        try {
          const { event: type, data } = JSON.parse(event.data)

          if (type === 'ping') {
            send('pong', { timestamp: Date.now() })
            return
          }

          emit(type, data)
        } catch (error) {
          console.error('Failed to parse WebSocket message:', error)
        }
      }

      ws.onerror = (error) => {
        state.lastError = error as Error
        state.connectionState = ConnectionState.ERROR
        emit('error', error)
      }

      ws.onclose = () => {
        state.connected = false
        state.connectionState = ConnectionState.DISCONNECTED
        emit('disconnected')

        // 自动重连
        if (state.reconnectAttempts < state.maxReconnectAttempts) {
          state.reconnectAttempts++
          state.connectionState = ConnectionState.RECONNECTING
          state.reconnectDelay *= 2 // 指数退避

          reconnectTimer = setTimeout(() => {
            connect()
          }, state.reconnectDelay)
        }
      }
    } catch (error) {
      state.lastError = error as Error
      state.connectionState = ConnectionState.ERROR
    }
  }

  const disconnect = () => {
    if (reconnectTimer) {
      clearTimeout(reconnectTimer)
    }
    if (ws) {
      ws.close()
      ws = null
    }
    state.connected = false
    state.connectionState = ConnectionState.DISCONNECTED
  }

  const send = (event: string, data: any = {}) => {
    if (ws && state.connected) {
      ws.send(JSON.stringify({ event, data }))
    }
  }

  const on = (event: string, callback: Function) => {
    if (!eventHandlers.has(event)) {
      eventHandlers.set(event, [])
    }
    eventHandlers.get(event)!.push(callback)

    // 返回取消订阅函数
    return () => {
      off(event, callback)
    }
  }

  const off = (event: string, callback: Function) => {
    const handlers = eventHandlers.get(event)
    if (handlers) {
      const index = handlers.indexOf(callback)
      if (index > -1) {
        handlers.splice(index, 1)
      }
    }
  }

  const emit = (event: string, data?: any) => {
    const handlers = eventHandlers.get(event) || []
    handlers.forEach(handler => handler(data))
  }

  return {
    state,
    connect,
    disconnect,
    send,
    on,
    off
  }
}
```

