##### Phase 2: RBAC 权限系统（第 2 天）

```typescript
// 1. 定义权限
// src/dashboard/auth/permissions.ts
export const Permissions = {
  ITERATION_VIEW: 'iteration:view',
  ITERATION_CREATE: 'iteration:create',
  ITERATION_DELETE: 'iteration:delete',
  AGENT_MANAGE: 'agent:manage',
  PROJECT_MANAGE: 'project:manage',
  USER_MANAGE: 'user:manage',
  SYSTEM_ADMIN: 'system:admin'
};

export const RolePermissions = {
  admin: Object.values(Permissions),
  developer: [
    Permissions.ITERATION_VIEW,
    Permissions.ITERATION_CREATE,
    Permissions.AGENT_MANAGE
  ],
  viewer: [
    Permissions.ITERATION_VIEW
  ]
};

// 2. RBAC 中间件
// src/dashboard/auth/rbac.middleware.ts
export function requirePermission(permission: string) {
  return async function (request, reply) {
    const user = request.user;

    if (!user) {
      return reply.code(401).send({ error: 'Unauthorized' });
    }

    const userPermissions = RolePermissions[user.role] || [];

    if (!userPermissions.includes(permission)) {
      return reply.code(403).send({ error: 'Forbidden' });
    }
  };
}

// 3. 应用权限
fastify.get('/iterations', {
  onRequest: [authMiddleware, requirePermission(Permissions.ITERATION_VIEW)]
}, async (request, reply) => {
  // ...
});

fastify.delete('/iterations/:id', {
  onRequest: [authMiddleware, requirePermission(Permissions.ITERATION_DELETE)]
}, async (request, reply) => {
  // ...
});
